(function () {
  "use strict";
  const select = (el, all = false) => {
    el = el.trim();
    if (all) {
      return [...document.querySelectorAll(el)];
    } else {
      return document.querySelector(el);
    }
  };
  const on = (type, el, listener, all = false) => {
    let selectEl = select(el, all);
    if (selectEl) {
      if (all) {
        selectEl.forEach((e) => e.addEventListener(type, listener));
      } else {
        selectEl.addEventListener(type, listener);
      }
    }
  };
  const onscroll = (el, listener) => {
    el.addEventListener("scroll", listener);
  };
  let navbarlinks = select("#navbar .scrollto", true);
  const navbarlinksActive = () => {
    let position = window.scrollY + 200;
    navbarlinks.forEach((navbarlink) => {
      if (!navbarlink.hash) return;
      let section = select(navbarlink.hash);
      if (!section) return;
      if (
        position >= section.offsetTop &&
        position <= section.offsetTop + section.offsetHeight
      ) {
        navbarlink.classList.add("active");
      } else {
        navbarlink.classList.remove("active");
      }
    });
  };
  window.addEventListener("load", navbarlinksActive);
  onscroll(document, navbarlinksActive);
  const scrollto = (el) => {
    let elementPos = select(el).offsetTop;
    window.scrollTo({
      top: elementPos,
      behavior: "smooth",
    });
  };
  let backtotop = select(".back-to-top");
  if (backtotop) {
    const toggleBacktotop = () => {
      if (window.scrollY > 100) {
        backtotop.classList.add("active");
      } else {
        backtotop.classList.remove("active");
      }
    };
    window.addEventListener("load", toggleBacktotop);
    onscroll(document, toggleBacktotop);
  }
  on("click", ".mobile-nav-toggle", function (e) {
    select("body").classList.toggle("mobile-nav-active");
    this.classList.toggle("bi-list");
    this.classList.toggle("bi-x");
  });
  on(
    "click",
    ".scrollto",
    function (e) {
      if (select(this.hash)) {
        e.preventDefault();
        let body = select("body");
        if (body.classList.contains("mobile-nav-active")) {
          body.classList.remove("mobile-nav-active");
          let navbarToggle = select(".mobile-nav-toggle");
          navbarToggle.classList.toggle("bi-list");
          navbarToggle.classList.toggle("bi-x");
        }
        scrollto(this.hash);
      }
    },
    true
  );
  window.addEventListener("load", () => {
    if (window.location.hash) {
      if (select(window.location.hash)) {
        scrollto(window.location.hash);
      }
    }
  });
  let preloader = select(".loader");
  if (preloader) {
    window.addEventListener("load", () => {
      preloader.remove();
    });
  }
  const typed = select(".typed");
  if (typed) {
    let typed_strings = typed.getAttribute("data-typed-items");
    typed_strings = typed_strings.split(",");
    new Typed(".typed", {
      strings: typed_strings,
      loop: true,
      typeSpeed: 100,
      backSpeed: 50,
      backDelay: 2000,
    });
  }
  window.addEventListener("load", () => {
    AOS.init({
      duration: 500,
      easing: "ease-in-out",
      once: true,
      mirror: false,
    });
  });
})();
document.addEventListener("DOMContentLoaded", function () {
  const elements = document.querySelectorAll(".fade");
  const offset = 100;
  function onScroll() {
    elements.forEach((el, index) => {
      if (el.getBoundingClientRect().top < window.innerHeight - offset) {
        setTimeout(() => {
          el.classList.add("show");
        }, index * 50);
      }
    });
  }
  window.addEventListener("scroll", onScroll);
  onScroll();
});
document.addEventListener("DOMContentLoaded", function () {
  const imagesList = document.getElementById("images-list");
  if (!imagesList) return;
  for (let i = 1; i <= 29; i++) {
    const imageSrc = `assets/img/certificate/img-${i}.avif`;
    const colDiv = document.createElement("div");
    colDiv.classList.add("col-6", "col-lg-4", "mb-5");
    const wrapper = document.createElement("div");
    wrapper.classList.add("skeleton-wrapper", "skeleton-cert");
    const imgElement = document.createElement("img");
    imgElement.src = imageSrc;
    imgElement.className = "img-fluid";
    imgElement.alt = "Tanapol's Certificate Images";
    imgElement.style.cursor = "pointer";
    imgElement.loading = "lazy";
    imgElement.onload = () => wrapper.classList.add("loaded");
    imgElement.onerror = () => wrapper.classList.add("loaded");
    if (imgElement.complete) wrapper.classList.add("loaded");
    imgElement.onclick = () => {
      document.getElementById("modalImage").src = imageSrc;
      new bootstrap.Modal(document.getElementById("imageModal")).show();
    };
    wrapper.appendChild(imgElement);
    colDiv.appendChild(wrapper);
    imagesList.appendChild(colDiv);
  }
});
document.addEventListener('DOMContentLoaded', function () {
  const prevBtn = document.querySelector('.paddlenav-arrow-previous');
  const nextBtn = document.querySelector('.paddlenav-arrow-next');
  const scroller = document.getElementById('scroller');
  function updateScrollerButtons() {
    const scrollLeft = scroller.scrollLeft;
    const maxScrollLeft = scroller.scrollWidth - scroller.clientWidth;
    if (scrollLeft <= 0) {
      prevBtn.disabled = true;
      prevBtn.classList.add('disabled');
      prevBtn.style.visibility = 'hidden';
    } else {
      prevBtn.disabled = false;
      prevBtn.classList.remove('disabled');
      prevBtn.style.visibility = 'visible';
    }
    if (scrollLeft >= maxScrollLeft - 1) {
      nextBtn.disabled = true;
      nextBtn.classList.add('disabled');
      nextBtn.style.visibility = 'hidden';
    } else {
      nextBtn.disabled = false;
      nextBtn.classList.remove('disabled');
      nextBtn.style.visibility = 'visible';
    }
  }
  prevBtn.addEventListener('click', function () {
    scroller.scrollBy({ left: -300, behavior: 'smooth' });
  });
  nextBtn.addEventListener('click', function () {
    scroller.scrollBy({ left: 300, behavior: 'smooth' });
  });
  scroller.addEventListener('scroll', updateScrollerButtons);
  window.addEventListener('load', updateScrollerButtons);
  updateScrollerButtons();
  setTimeout(updateScrollerButtons, 500);
});
var currentYear = new Date().getFullYear();
document.getElementById('current-year').textContent = currentYear;
document.addEventListener("DOMContentLoaded", function () {
  document.querySelectorAll(".skeleton-wrapper img").forEach(function (img) {
    const wrapper = img.parentElement;
    if (img.complete) {
      wrapper.classList.add("loaded");
    } else {
      img.addEventListener("load", function () { wrapper.classList.add("loaded"); });
      img.addEventListener("error", function () { wrapper.classList.add("loaded"); });
    }
  });
});